@namespace Lumeo

@{
    var context = new ContextMenuRadioGroupContext(Value, EventCallback.Factory.Create<string>(this, OnValueSelected));
}

<CascadingValue Value="context" IsFixed="false">
    <div role="group" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Value { get; set; }
    [Parameter] public EventCallback<string> ValueChanged { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private async Task OnValueSelected(string value)
    {
        Value = value;
        await ValueChanged.InvokeAsync(value);
    }

    public record ContextMenuRadioGroupContext(string? Value, EventCallback<string> OnSelect);
}

@namespace Lumeo

<button type="button" role="menuitemradio" aria-checked="@IsSelected.ToString().ToLower()" class="@CssClass" @onclick="Select" @attributes="AdditionalAttributes">
    <span class="flex h-3.5 w-3.5 items-center justify-center">
        @if (IsSelected)
        {
            <Blazicon Svg="Lucide.Circle" class="h-2 w-2 fill-current" />
        }
    </span>
    @ChildContent
</button>

@code {
    [CascadingParameter] public ContextMenuRadioGroup.ContextMenuRadioGroupContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter, EditorRequired] public string Value { get; set; } = "";
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool IsSelected => Context.Value == Value;

    private string CssClass => $"relative flex w-full cursor-default select-none items-center gap-2 rounded-sm py-1.5 pl-8 pr-2 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground focus:bg-accent focus:text-accent-foreground {Class}".Trim();

    private async Task Select() => await Context.OnSelect.InvokeAsync(Value);
}

@namespace Lumeo

<div class="@CssClass" role="none" @attributes="AdditionalAttributes"></div>

@code {
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"-mx-1 my-1 h-px bg-border {Class}".Trim();
}

@namespace Lumeo

<div class="@CssClass" aria-expanded="@Context.IsOpen" @oncontextmenu="HandleContextMenu" @oncontextmenu:preventDefault @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [CascadingParameter] public ContextMenu.ContextMenuContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"inline-flex {Class}".Trim();

    private async Task HandleContextMenu(MouseEventArgs e)
    {
        await Context.SetPosition.InvokeAsync((e.ClientX, e.ClientY));
        await Context.SetOpen.InvokeAsync(true);
    }
}
